mapper.select:
SELECT hotWalletAddress.userId AS userId, hotWalletAddress.userAccount AS userAccount, hotWalletAddress.trcAddress AS trcAddress, hotWalletAddress.trcAddressBalance AS trcAddressBalance, hotWalletAddress.ercAddress AS ercAddress, hotWalletAddress.ercAddressBalance AS ercAddressBalance, hotWalletAddress.trcOutAddressNo AS trcOutAddressNo, hotWalletAddress.ercOutAddressNo AS ercOutAddressNo, (hotWalletAddress.trcAddressBalance + hotWalletAddress.ercAddressBalance) AS sumBalance FROM (SELECT MAX(hwa.user_id) AS userId, MAX(hwa.user_account) AS userAccount, MAX(IF(hwa.chain_type = 'TRON',hwa.address,'')) AS trcAddress, MAX(IF(hwa.chain_type = 'TRON',hwa.balance,'')) AS trcAddressBalance, MAX(IF(hwa.chain_type = 'ETH',hwa.address,'')) AS ercAddress, MAX(IF(hwa.chain_type = 'ETH',hwa.balance,'')) AS ercAddressBalance, MAX(IF(hwa.chain_type = 'TRON',hwa.out_address_no,'')) AS trcOutAddressNo, MAX(IF(hwa.chain_type = 'ETH',hwa.out_address_no,'')) AS ercOutAddressNo FROM hot_wallet_address hwa WHERE hwa.site_code = #{vo.siteCode} AND hwa.wallet_user_type = 'USER'
AND hwa.user_id = #{vo.userId}
AND hwa.user_account = #{vo.userAccount}
AND hwa.chain_type = 'TRON' AND hwa.address LIKE CONCAT('%', #{vo.trcAddress}, '%')
AND hwa.chain_type = 'ETH' AND hwa.address LIKE CONCAT('%', #{vo.ercAddress}, '%')
GROUP BY hwa.user_id) as hotWalletAddress ORDER BY sumBalance DESC

SELECT '总计' AS userId, SUM(IF(hwa.chain_type = 'TRON',hwa.balance,'')) AS trcAddressBalance, SUM(IF(hwa.chain_type = 'ETH',hwa.balance,'')) AS ercAddressBalance FROM hot_wallet_address hwa WHERE hwa.site_code = #{vo.siteCode} AND hwa.wallet_user_type = 'USER'
AND hwa.user_id = #{vo.userId}
AND hwa.user_account = #{vo.userAccount}
AND hwa.chain_type = 'TRON' AND hwa.address LIKE CONCAT('%', #{vo.trcAddress}, '%')
AND hwa.chain_type = 'ETH' AND hwa.address LIKE CONCAT('%', #{vo.ercAddress}, '%')

SELECT COUNT(hotWalletAddress.userId) FROM ( SELECT max(hwa.user_id) AS userId FROM hot_wallet_address hwa WHERE hwa.site_code = #{vo.siteCode} AND hwa.wallet_user_type = 'USER'
AND hwa.user_id = #{vo.userId}
AND hwa.user_account = #{vo.userAccount}
AND hwa.chain_type = 'TRON' AND hwa.address LIKE CONCAT('%', #{vo.trcAddress}, '%')
AND hwa.chain_type = 'ETH' AND hwa.address LIKE CONCAT('%', #{vo.ercAddress}, '%')
GROUP BY hwa.user_id) as hotWalletAddress
